INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ねぇねぇ、騎士クン\n手伝ってあげようよ～", 0, 1, "お！\nあそこに困ってそうな人発見！", 0, 1, 2, "春咲 ひより", 0, 0, 0, 1.4, 1001, "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("わ、わたし、\nなに言ってるんだろ\nあはは…", 0, 1, "大切な人を\n守れるようになりたい…って", 0, 1, 2, "草野 優衣", 0, 0, 0, 1.4, 1002, "みんなみたいに\nわたしも強くならなきゃ", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("少しは磨かれると思いますよ。", 0, 1, "キミに必要な集中力と感性が", 0, 1, 2, "士条 怜", 0, 0, 0, 1.4, 1003, "フェンシングを始めてみては？", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("みそぎはねぇ、\nかくれんぼやりたい！", 0, 1, "今日はなにして遊ぶ？", 0, 1, 2, "穂高 みそぎ", 0, 0, 0, 1.5, 1004, "ねぇ、にいちゃん！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("私といっしょに…\nいかない？", 0, 1, "ねぇ…", 0, 1, 2, "風宮 あかり", 0, 0, 0, 1.4, 1006, "風宮あかりです", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("食べ物の恨みは怖いのー", 0, 1, "プリンたべたいのー", 0, 1, 2, "出雲 宮子", 0, 0, 0, 1.5, 1007, "出雲宮子なのー", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("いいよ。\n見られることは運命さ…", 0, 1, "キミもボクの美貌に\n吸い寄せられたんだね。", 0, 1, 2, "虹村 雪", 0, 0, 0, 1.4, 1008, "ボクは虹村雪。", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("人呼んで「疾風の冥姫」!!", 0, 1, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 0, 1, 2, "柊杏奈", 0, 0, 0, 1.4, 1009, "フッ…聞いて後悔するがいい！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ほんまおおきにやわ～♪", 0, 1, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 0, 1, 2, "姫宮 真歩", 0, 0, 0, 1.5, 1010, "マホマホ王国のプリンセス、\nまほ姫どす", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ここで会ったが\n100年目～！", 0, 1, "生き別れたお兄ちゃんを探して\n三千世界！", 0, 1, 2, "衣之咲 璃乃", 0, 0, 0, 1.4, 1011, "衣之咲璃乃です！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("…って、お願い！\n誰にも言わないでおいて～！", 0, 1, "ち、超能力って…\n何のことかな～？", 0, 1, 2, "柏崎 初音", 0, 0, 0, 1.4, 1012, "私はハツネ、\n結構強いんだよ。\nきらーん☆", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ヒデサイまぢ\nGF（グッドフィーリング）～♪", 0, 1, "一応カリスマ読モJKやってまっす！", 0, 1, 2, "美波 鈴奈", 0, 0, 0, 1.4, 1016, "ちょす！\n美波鈴奈だよ～♪", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("でも、沖縄もとってもいいとこさー", 0, 1, "東京は遊園地みたいなところさー", 0, 1, 2, "喜屋武 香織", 0, 0, 0, 1.4, 1017, "はいたーい。\n喜屋武香織さー。", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("イオちゃんって呼んでね。", 0, 1, "先生って呼ばれるのは\nくすぐったいから", 0, 1, 2, "支倉 伊緒", 0, 0, 0, 1.4, 1018, "支倉伊緒です。", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ミミをおいてかないでぇ～", 0, 1, "あ！/\お兄ちゃ～ん\nまってよ～", 0, 1, 2, "茜 ミミ", 0, 0, 0, 1.5, 1020, "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ふぇぇぇぇぇん……", 0, 1, "あの……\nふぇ……", 0, 1, 2, "栗林 くるみ", 0, 0, 0, 1.5, 1021, "あ…あの…えっと…\n栗…林…くるみ…です……", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("なんてありがとうございます！", 0, 1, "こんな私に貴重な時間を\n割いていただき、", 0, 1, 2, "風宮 より", 0, 0, 0, 1.4, 1022, "風宮よりです。\nあああああ！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("私こっち行きたいー\nね、早く早くー", 0, 1, "おにいちゃんどこいくの？\nえ？", 0, 1, 2, "北条 綾音", 0, 0, 0, 1.5, 1023, "私、アヤネ！\nぷうきちと一緒についてってあげるね！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("これて何か違う…\nあああすみません！", 0, 1, "ふ、不束者ですが\nどうぞ末永く…って、", 0, 1, 2, "天野 すずめ", 0, 0, 0, 1.4, 1025, "わっ…わっ…私、\n天野すずめといいます！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("離しませんわ………\n絶対に…!!", 0, 1, "あなたは…運命の……\n伴侶……", 0, 1, 2, "倉石 恵理子", 0, 0, 0, 1.4, 1027, "……クスクス…私は\n…倉石恵理子……", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("…そうでしょ？？", 0, 1, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 0, 1, 2, "佐々木 咲恋", 0, 0, 0, 1.4, 1028, "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("あはは、\n私もまだまだだなぁ～", 0, 1, "ぇっと…\nキミ、私のこと知らないの?!", 0, 1, 2, "桜井 望", 0, 0, 0, 1.4, 1029, "桜井望だよ！\nよろしくねっ", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ショーグン、\nワタシと一緒に天下統一デース！", 0, 1, "初めまして、\n私はニノン・ジュベール申すデス！", 0, 1, 2, "ニノン・ジュベール", 0, 0, 0, 1.4, 1030, "デケデケデンっ！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("おかしいですね……", 0, 1, "でもって私の隣にいるのが……\nえ、見えない？", 0, 1, 2, "上喜 しのぶ", 0, 0, 0, 1.4, 1031, "上喜しのぶです。\n手元のドクロが父です。", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("そう、\nオラのボケに突っ込める相方が…！", 0, 1, "けんども\nそれには足りないモンが…", 0, 1, 2, "野戸まひる", 0, 0, 0, 1.5, 1033, "目指すはビッグな\nお笑い芸人だっぺ！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ちょ\nちょっと一杯飲んできます…！", 0, 1, "ちょっと緊張しちゃって…", 0, 1, 2, "綾瀬 ゆかり", 0, 0, 0, 1.4, 1034, "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("これ以上お話しすることは…\nないです！", 0, 1, "知らない人とは話しちゃいけないので", 0, 1, 2, "氷川 鏡華", 0, 0, 0, 1.5, 1036, "氷川鏡華…です", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 0, 1, "……あ、アラーム。", 0, 1, 2, "柏崎 栞", 0, 0, 0, 1.4, 1038, "柏崎…栞です。", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("野に咲く花が、\n唯一の話相手です。", 0, 1, "私、一人も友達がいなくて……", 0, 1, 2, "双葉 碧", 0, 0, 0, 1.4, 1040, "ふ、双葉碧です。", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("そう思っています。", 0, 1, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 0, 1, 2, "三角 千歌", 0, 0, 0, 1.4, 1042, "三角千歌です。", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("う、疑ってすまなかったな…", 0, 1, "あぁ？\nお前のそいつの仲間か？", 0, 1, 2, "安芸 真琴", 0, 0, 0, 1.4, 1043, "安芸真琴だ。", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 0, 1, "生けとし生ける全ての者よ！", 0, 1, 2, "イリヤ・オーンスタイン", 0, 0, 0, 1.4, 1044, "わらわこそは夜を総べる者！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ｌク、クウカに何かご用ですか!?", 0, 1, "ぐふふふふ……はっ！", 0, 1, 2, "遠見 空花", 0, 0, 0, 1.4, 1045, "そこで騎士は妖精を乱暴に……", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("う～ん…\n猫ってホントに最高にゃ～♪", 0, 1, "自由気ままで♪\n寝て遊んで、食べてケンカして…", 0, 1, 2, "宮坂たまき", 0, 0, 0, 1.4, 1046, "宮坂たまきにゃ♪\n猫はいいにゃよ？", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("…と思ったら\nバイトの時間だ！\nまたあとでね！", 0, 1, "それでは早速クエストに…", 0, 1, 2, "大神 美冬", 0, 0, 0, 1.4, 1048, "大神美冬よ！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("お姉ちゃんがぜ～んぶ\nやってあげるからね！", 0, 1, "クエストもバトルも\n掃除も洗濯も", 0, 1, 2, "星野静流", 0, 0, 0, 1.4, 1049, "星野静流だよ！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 0, 1, "見ての通りの\nセクシー美少女で", 0, 1, 2, "玉泉美咲", 0, 0, 0, 1.5, 1050, "アタシは玉泉美咲。", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("？？？？", 0, 1, "？？？？", 0, 1, 2, "リマ", 0, 0, 0, 1.4, 1052, "？？？", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("そ、そこまでいうなら\nもらってやる", 0, 1, "菓子でつろうなどと\n稚拙な策を……", 0, 1, 2, "モニカ・ヴァイスヴィント", 0, 0, 0, 1.5, 1053, "モニカ・ヴァイスヴィントだ。", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("そ、そこまでいうなら\nもらってやる", 0, 1, "菓子でつろうなどと\n稚拙な策を……", 0, 1, 2, "ペコリーヌ", 0, 0, 0, 1.5, 1058, "モニカ・ヴァイスヴィントだ。", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("そ、そこまでいうなら\nもらってやる", 0, 1, "菓子でつろうなどと\n稚拙な策を……", 0, 1, 2, "コッコロ", 0, 0, 0, 1.5, 1059, "モニカ・ヴァイスヴィントだ。", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("そ、そこまでいうなら\nもらってやる", 0, 1, "菓子でつろうなどと\n稚拙な策を……", 0, 1, 2, "キャル", 0, 0, 0, 1.5, 1060, "モニカ・ヴァイスヴィントだ。", 1);
